import{_ as a,o as n,c as t,ag as i}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"E-mailintegratie","description":"","frontmatter":{},"headers":[],"relativePath":"nl/settings/email.md","filePath":"nl/settings/email.md"}'),r={name:"nl/settings/email.md"};function l(o,e,s,d,u,m){return n(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="e-mailintegratie" tabindex="-1">E-mailintegratie <a class="header-anchor" href="#e-mailintegratie" aria-label="Permalink to &quot;E-mailintegratie&quot;">​</a></h1><p>Configureer hoe MyCompanyDesk e-mails verstuurt naar je klanten — van factuurverzending tot betalingsherinneringen.</p><h2 id="e-mailverzendmethoden" tabindex="-1">E-mailverzendmethoden <a class="header-anchor" href="#e-mailverzendmethoden" aria-label="Permalink to &quot;E-mailverzendmethoden&quot;">​</a></h2><p>MyCompanyDesk ondersteunt drie manieren om e-mails te versturen:</p><h3 id="_1-ingebouwde-e-mail-standaard" tabindex="-1">1. Ingebouwde e-mail (standaard) <a class="header-anchor" href="#_1-ingebouwde-e-mail-standaard" aria-label="Permalink to &quot;1. Ingebouwde e-mail (standaard)&quot;">​</a></h3><p>Standaard worden e-mails verstuurd via de eigen e-mailservice van MyCompanyDesk. Geen configuratie nodig.</p><h3 id="_2-gmail-integratie" tabindex="-1">2. Gmail-integratie <a class="header-anchor" href="#_2-gmail-integratie" aria-label="Permalink to &quot;2. Gmail-integratie&quot;">​</a></h3><p>Verstuur e-mails rechtstreeks vanuit je Gmail-account:</p><ol><li>Ga naar <strong>Instellingen &gt; Communicatie &gt; E-mail</strong></li><li>Klik op <strong>Gmail koppelen</strong></li><li>Autoriseer MyCompanyDesk om namens jou te versturen via Google OAuth</li><li>E-mails worden nu verzonden vanaf je Gmail-adres</li></ol><p><strong>Voordelen:</strong></p><ul><li>E-mails tonen je Gmail-adres als afzender</li><li>Verzonden e-mails verschijnen in je Gmail Verzonden-map</li><li>Betere bezorgbaarheid (je eigen domeinreputatie)</li></ul><h3 id="_3-outlook-microsoft-integratie" tabindex="-1">3. Outlook / Microsoft-integratie <a class="header-anchor" href="#_3-outlook-microsoft-integratie" aria-label="Permalink to &quot;3. Outlook / Microsoft-integratie&quot;">​</a></h3><p>Verstuur vanuit je Outlook of Microsoft 365-account:</p><ol><li>Ga naar <strong>Instellingen &gt; Communicatie &gt; E-mail</strong></li><li>Klik op <strong>Outlook koppelen</strong></li><li>Autoriseer via Microsoft OAuth</li><li>E-mails worden verstuurd vanaf je Outlook-adres</li></ol><h3 id="_4-aangepaste-smtp" tabindex="-1">4. Aangepaste SMTP <a class="header-anchor" href="#_4-aangepaste-smtp" aria-label="Permalink to &quot;4. Aangepaste SMTP&quot;">​</a></h3><p>Voor volledige controle gebruik je je eigen SMTP-server:</p><ol><li>Ga naar <strong>Instellingen &gt; Communicatie &gt; E-mail</strong></li><li>Vul je SMTP-gegevens in: <ul><li><strong>Host</strong> — SMTP-serveradres</li><li><strong>Poort</strong> — Serverpoort (587 voor TLS, 465 voor SSL)</li><li><strong>Gebruikersnaam</strong> — SMTP-login</li><li><strong>Wachtwoord</strong> — SMTP-wachtwoord</li></ul></li><li>Klik op <strong>Verbinding testen</strong> om te verifieren dat het werkt</li><li>Sla op</li></ol><h2 id="e-mailsjablonen" tabindex="-1">E-mailsjablonen <a class="header-anchor" href="#e-mailsjablonen" aria-label="Permalink to &quot;E-mailsjablonen&quot;">​</a></h2><p>Pas de e-mails aan die worden verstuurd met je facturen en herinneringen.</p><h3 id="factuur-e-mailsjabloon" tabindex="-1">Factuur-e-mailsjabloon <a class="header-anchor" href="#factuur-e-mailsjabloon" aria-label="Permalink to &quot;Factuur-e-mailsjabloon&quot;">​</a></h3><p>De standaard e-mail die wordt verstuurd bij het bezorgen van een factuur. Pas aan:</p><ul><li><strong>Onderwerpregel</strong> — Het e-mailonderwerp (ondersteunt variabelen zoals factuurnummer)</li><li><strong>Inhoud</strong> — De berichttekst</li><li><strong>Taal</strong> — Stel sjablonen per taal in</li></ul><h3 id="herinnerings-e-mailsjabloon" tabindex="-1">Herinnerings-e-mailsjabloon <a class="header-anchor" href="#herinnerings-e-mailsjabloon" aria-label="Permalink to &quot;Herinnerings-e-mailsjabloon&quot;">​</a></h3><p>De e-mail die wordt verstuurd bij het opvolgen van achterstallige facturen. Pas dezelfde velden aan als hierboven, maar met een urgentere toon.</p><h3 id="voorbeeld-bekijken" tabindex="-1">Voorbeeld bekijken <a class="header-anchor" href="#voorbeeld-bekijken" aria-label="Permalink to &quot;Voorbeeld bekijken&quot;">​</a></h3><p>Voor het versturen kun je elke e-mail bekijken om precies te zien wat je klant ontvangt:</p><ul><li>Gerenderde HTML met je huisstijl</li><li>PDF-bijlagevoorbeeld</li><li>Betaallink-opname</li></ul><h2 id="variabelen" tabindex="-1">Variabelen <a class="header-anchor" href="#variabelen" aria-label="Permalink to &quot;Variabelen&quot;">​</a></h2><p>E-mailsjablonen ondersteunen dynamische variabelen:</p><table tabindex="0"><thead><tr><th>Variabele</th><th>Beschrijving</th></tr></thead><tbody><tr><td><code>{invoice_number}</code></td><td>Het factuurnummer</td></tr><tr><td><code>{customer_name}</code></td><td>Naam van de klant</td></tr><tr><td><code>{amount}</code></td><td>Totaal factuurbedrag</td></tr><tr><td><code>{due_date}</code></td><td>Vervaldatum</td></tr><tr><td><code>{company_name}</code></td><td>Je bedrijfsnaam</td></tr><tr><td><code>{payment_link}</code></td><td>Link naar online betaling</td></tr></tbody></table><h2 id="meldingen" tabindex="-1">Meldingen <a class="header-anchor" href="#meldingen" aria-label="Permalink to &quot;Meldingen&quot;">​</a></h2><p>Configureer welke e-mailmeldingen je ontvangt:</p><ul><li><strong>Factuur betaald</strong> — Ontvang een melding wanneer een klant betaalt</li><li><strong>Offerteaanvraag ontvangen</strong> — Melding bij nieuwe offerteaanvragen</li><li><strong>Teamactiviteit</strong> — Updates over acties van teamleden</li></ul><p>Meldingsvoorkeuren kun je instellen in je <a href="/nl/account/profile">Profiel</a>.</p><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Koppel Gmail of Outlook voor de beste bezorgbaarheid</li><li>Test je e-mailsjabloon altijd voordat je je eerste factuur verstuurt</li><li>Stel taalspecifieke sjablonen in als je klanten in meerdere talen bedient</li><li>Gebruik het herinneringssjabloon voor professionele opvolging van achterstallige facturen</li></ul>',36)])])}const c=a(r,[["render",l]]);export{h as __pageData,c as default};
